import { useState, useEffect, useCallback } from 'react';
import { api, apiPost, apiPut, apiDelete } from '../utils/api';

export default function useWatchlists() {
  const [watchlists, setWatchlists] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const normalizeWatchlist = (w) => ({
    ...w,
    symbols: (w.symbols || []).map(s =>
      typeof s === 'string'
        ? { symbol: s, region: 'US', addedDate: null, notes: '' }
        : s
    ),
  });

  const refresh = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await api('/watchlists');
      if (data) {
        const list = Array.isArray(data) ? data : data.watchlists || [];
        setWatchlists(list.map(normalizeWatchlist));
      } else {
        setError('Failed to load watchlists');
      }
    } catch (e) {
      setError(e.message || 'Failed to load watchlists');
    }
    setLoading(false);
  }, []);

  useEffect(() => {
    refresh();
  }, [refresh]);

  const getWatchlist = useCallback(async (id) => {
    const data = await api('/watchlists/' + id);
    if (data) return normalizeWatchlist(data);
    return null;
  }, []);

  const createWatchlist = useCallback(async (name, desc) => {
    const created = await apiPost('/watchlists', { name, description: desc });
    if (created) { await refresh(); return created; }
    return null;
  }, [refresh]);

  const updateWatchlist = useCallback(async (id, updates) => {
    const result = await apiPut('/watchlists/' + id, updates);
    if (result) { await refresh(); return result; }
    return null;
  }, [refresh]);

  const deleteWatchlist = useCallback(async (id) => {
    const result = await apiDelete('/watchlists/' + id);
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  const addSymbol = useCallback(async (watchlistId, symbol) => {
    const result = await apiPost('/watchlists/' + watchlistId + '/symbols', { symbol });
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  const removeSymbol = useCallback(async (watchlistId, symbol) => {
    const result = await api('/watchlists/' + watchlistId + '/symbols', {
      method: 'DELETE',
      body: JSON.stringify({ symbol }),
    });
    if (result) { await refresh(); return true; }
    return false;
  }, [refresh]);

  const importWatchlist = useCallback(async (payload) => {
    // payload: { name, symbols, format } or FormData
    const result = await apiPost('/watchlists/import', payload);
    if (result) { await refresh(); return result; }
    return null;
  }, [refresh]);

  const exportWatchlist = useCallback(async (payload) => {
    // payload: { watchlist_id, format }
    const result = await apiPost('/watchlists/export', payload);
    return result;
  }, []);

  return {
    watchlists, loading, error,
    getWatchlist, createWatchlist, updateWatchlist, deleteWatchlist,
    addSymbol, removeSymbol,
    importWatchlist, exportWatchlist,
    refresh,
  };
}
